class Solution:
    def minAnagramLength(self, s: str) -> int:
        from collections import Counter

        n = len(s)
        freq = Counter(s)

        # The minimum possible length of t is the least common multiple (LCM)
        # of the frequencies of the characters in s.
        # However, since t must be an anagram of some substring of s, we need to find
        # the smallest length that can evenly divide the frequencies of all characters.

        # We can try all possible lengths from 1 to n and check if it's possible
        # to split the string into anagrams of length l.
        for l in range(1, n + 1):
            if n % l == 0:
                # Check if each character's frequency is divisible by (n // l)
                valid = True
                for count in freq.values():
                    if count % (n // l) != 0:
                        valid = False
                        break
                if valid:
                    return l
        return n
